const trades = $input.all().map(i => i.json);
const wh = $('Webhook').first().json;
return [{ json: { trades, sheet_id: wh.body.sheet_id, email: wh.body.email || '' } }];

// Construir config desde filas campo/valor
const configRows = $input.all().map(i => i.json);
const config = configRows.reduce((acc, row) => {
  const k = row.campo || row.Campo || Object.values(row)[0];
  const v = row.valor || row.Valor || Object.values(row)[1];
  if (k) acc[k.toLowerCase()] = v;
  return acc;
}, {});

const trades = $('Preparar Datos').first().json.trades;
const mes = (config.mes || 'MES').toUpperCase();
const anio = String(config.anio || new Date().getFullYear());
const total = config.total || '+0.00%';
const logoUrl = 'https://raw.githubusercontent.com/Dtolosag/proyecto-m71/main/assets/logo-m71.png';

// Generar filas de la tabla
const rowsHtml = trades.map(t => {
  const fecha = t.fecha || t.Fecha || '';
  const activo = t.activo || t.Activo || '';
  const tipo = t.tipo || t.Tipo || '';
  const resultado = String(t.resultado || t.Resultado || '');

  let cls = '';
  const num = parseFloat(resultado.replace('%', ''));
  if (resultado === 'BE') cls = '';
  else if (!isNaN(num) && num > 0) cls = 'pos';
  else if (!isNaN(num) && num < 0) cls = 'neg';

  return `<tr><td>${fecha}</td><td>${activo}</td><td>${tipo}</td><td class="${cls}">${resultado}</td></tr>`;
}).join('');

const totalNum = parseFloat(total.replace('%', '').replace('+', ''));
const totalCls = totalNum > 0 ? 'pos' : totalNum < 0 ? 'neg' : '';

const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@700;800;900&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html,body{
  background:#0d0d0d;color:#fff;
  font-family:'Barlow Condensed',Impact,'Arial Narrow',sans-serif;
  -webkit-print-color-adjust:exact;print-color-adjust:exact;
}
.page{
  width:794px;min-height:1123px;
  background:#0d0d0d;
  padding:55px 50px 45px;
  display:flex;flex-direction:column;align-items:center;
}
.header{text-align:center;margin-bottom:48px}
.t1{font-size:74px;font-weight:900;color:#fff;text-transform:uppercase;letter-spacing:5px;line-height:1;display:block}
.t2{font-size:74px;font-weight:900;color:#3dff50;text-transform:uppercase;letter-spacing:5px;line-height:1;display:block}
table{width:100%;border-collapse:collapse}
thead th{
  background:#191919;color:#777;font-size:13px;font-weight:700;
  text-transform:uppercase;letter-spacing:2px;
  padding:15px 10px;text-align:center;border-bottom:1px solid #2e2e2e;
}
tbody tr{border-bottom:1px solid #1e1e1e}
tbody td{padding:14px 10px;text-align:center;font-size:19px;font-weight:700;color:#fff}
.pos{color:#3dff50}
.neg{color:#ff4040}
.total-sec{
  margin-top:32px;width:100%;
  padding-top:20px;border-top:1px solid #2a2a2a;
  text-align:center;
}
.t-label{font-size:28px;font-weight:900;text-transform:uppercase;letter-spacing:3px;color:#fff}
.t-val{font-size:28px;font-weight:900;margin-left:14px}
.logo-sec{margin-top:48px;text-align:center}
.logo-sec img{height:58px;max-width:320px}
</style>
</head><body>
<div class="page">
  <div class="header">
    <span class="t1">Resultados</span>
    <span class="t2">${mes} ${anio}</span>
  </div>
  <table>
    <thead><tr><th>Fecha</th><th>Activo Operado</th><th>Tipo de Operaci\u00f3n</th><th>Resultado (%)</th></tr></thead>
    <tbody>${rowsHtml}</tbody>
  </table>
  <div class="total-sec">
    <span class="t-label">Total ${mes}:</span>
    <span class="t-val ${totalCls}">${total}</span>
  </div>
  <div class="logo-sec">
    <img src="${logoUrl}" alt="M71 Trading" onerror="this.style.display='none'"/>
  </div>
</div></body></html>`;

const buf = Buffer.from(html, 'utf-8');
return [{
  json: { mes, anio },
  binary: {
    htmlFile: {
      data: buf.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html',
      fileSize: buf.length
    }
  }
}];
